#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <unistd.h>
#include <stdint.h>
#include <sys/time.h>
#include <cuda.h>

/* Inline timer definitions */
static __inline__ uint64_t rdtsc() 
{
    uint32_t lo, hi;
    __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
    return (uint64_t)hi << 32 | lo;
}

static unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x)
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

void init(int argc, char** argv)
{
    if(argc==4){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        // argv[3] is pyramidHeight, handled in run()
    }else{
        printf("Usage: pathfinder width num_of_steps pyramid_height\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; n<rows; n++)
        wall[n]=data+cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]);
        }
        printf("\n");
    }
#endif
}

#define BLOCK_SIZE 256

__global__ void dynproc_kernel(
    int iteration,
    int *gpuWall,
    int *gpuSrc,
    int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border)
{
    __shared__ int prev[BLOCK_SIZE];
    __shared__ int result[BLOCK_SIZE];

    int bx = blockIdx.x;
    int tx = threadIdx.x;

    // each block handles a segment of the row
    int b_ind = bx * (BLOCK_SIZE - 2 * border) - border;
    int e_ind = b_ind + BLOCK_SIZE - 1;

    int small_block_cols = BLOCK_SIZE - 2 * border;

    int g_ind = b_ind + tx;

    int w = cols;

    // load initial data
    if (IN_RANGE(g_ind, 0, w-1))
        prev[tx] = gpuSrc[g_ind];
    else
        prev[tx] = INT_MAX / 2;

    __syncthreads();

    bool computed;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;
        if (IN_RANGE(tx, border, BLOCK_SIZE - border - 1) &&
            IN_RANGE(g_ind, 0, w-1))
        {
            computed = true;
            int left = (tx > 0) ? prev[tx-1] : (INT_MAX/2);
            int right = (tx < BLOCK_SIZE-1) ? prev[tx+1] : (INT_MAX/2);
            int up = prev[tx];
            int min_val = MIN(up, MIN(left, right));
            int curr_step = startStep + i + 1;
            if (curr_step < rows)
                result[tx] = gpuWall[curr_step * w + g_ind] + min_val;
            else
                result[tx] = min_val;
        }
        __syncthreads();

        if (i == iteration - 1)
            break;

        if (computed)
            prev[tx] = result[tx];
        __syncthreads();
    }

    if (computed && IN_RANGE(g_ind, 0, w-1))
        gpuResults[g_ind] = result[tx];
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int pyramidHeight = atoi(argv[3]);
    printf("pyramidHeight: %d\n", pyramidHeight);
    printf("gridSize: [%d]\n", cols);
    printf("blockSize: %d\n", BLOCK_SIZE);

    int *gpuWall, *gpuResult[2];
    int size = rows * cols;

    cudaMalloc((void**)&gpuWall, size * sizeof(int));
    cudaMalloc((void**)&gpuResult[0], cols * sizeof(int));
    cudaMalloc((void**)&gpuResult[1], cols * sizeof(int));

    cudaMemcpy(gpuWall, data, size * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(gpuResult[0], result, cols * sizeof(int), cudaMemcpyHostToDevice);

    int src = 0, dst = 1;

    pin_stats_reset();

    for (int t = 0; t < rows - 1; t += pyramidHeight)
    {
        int iteration = MIN(pyramidHeight, rows - 1 - t);
        int border = iteration;

        int small_block_cols = BLOCK_SIZE - 2 * border;
        int blockCols = (cols + small_block_cols - 1) / small_block_cols;

        dim3 dimBlock(BLOCK_SIZE, 1);
        dim3 dimGrid(blockCols, 1);

        dynproc_kernel<<<dimGrid, dimBlock>>>(
            iteration,
            gpuWall,
            gpuResult[src],
            gpuResult[dst],
            cols,
            rows,
            t,
            border);

        cudaDeviceSynchronize();

        int tmp = src;
        src = dst;
        dst = tmp;
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    cudaMemcpy(result, gpuResult[src], cols * sizeof(int), cudaMemcpyDeviceToHost);

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");

    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    cudaFree(gpuWall);
    cudaFree(gpuResult[0]);
    cudaFree(gpuResult[1]);

    delete [] data;
    delete [] wall;
    delete [] result;
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}
